 	function getCyclableStyle(feature) {
    const hierarchy = parseInt(feature.properties.hierarchisation);
    const baseColor = 'green';

    let weight = 1;
    let dashArray = null;

    switch (hierarchy) {
      case 1:
        weight = 4;
        break;
      case 2:
        weight = 2;
        break;
      case 3:
        weight = 1;
        break;
      case 4:
        weight = 0.8;
        break;
      case 5:
      default:
        weight = 0.8;
        dashArray = '4,6'; // style plus léger
        break;
    }

    return {
      color: baseColor,
      weight: weight,
      opacity: 1,
	  
      dashArray: dashArray
    };
  } 
 
