  // Créer la couche du réseau cyclable
const cyclableLayer = L.geoJSON(reseauCyclable, {
  style: getCyclableStyle
}).addTo(map); // Par défaut, visible

// Checkbox pour afficher/masquer le réseau cyclable
document.getElementById('toggle-cyclable').addEventListener('change', function() {
  if (this.checked) {
    map.addLayer(cyclableLayer);
  } else {
    map.removeLayer(cyclableLayer);
  }
});
